=== app-producer image command ===
    "command": [
        "/bin/sh",
        "-c",
        "set -e\nbase=\"http://rabbitmq:15672/api\"\nvhost=\"%2Fapp\"\nqueue=\"app-queue\"\nauth=\"${APP_USER}:${APP_PASS}\"\nfor i in $(seq 1 60); do\n  if curl -s -u \"$auth\" \"$base/vhosts\" >/dev/null; then\n    break\n  fi\n  sleep 2\ndone\npayload='{\"durable\":true,\"auto_delete\":false,\"arguments\":{\"x-queue-type\":\"classic\",\"x-queue-mode\":\"lazy\"}}'\ncode=$(curl -s -o /tmp/resp -w \"%{http_code}\" -u \"$auth\" \\\n  -H \"content-type: application/json\" \\\n  -XPUT \"$base/queues/${vhost}/${queue}\" -d \"$payload\")\nif [ \"$code\" -ge 300 ]; then\n  echo \"app-producer: failed to declare queue in vhost /app: $(cat /tmp/resp)\"\n  exit 1\nfi\ni=0\nwhile true; do\n  body='{\"properties\":{},\"routing_key\":\"'\"${queue}\"'\",\"payload\":\"msg-'\"${i}\"'\",\"payload_encoding\":\"string\"}'\n  code=$(curl -s -o /tmp/pubresp -w \"%{http_code}\" -u \"$auth\" \\\n    -H \"content-type: application/json\" \\\n    -XPOST \"$base/exchanges/${vhost}/amq.default/publish\" -d \"$body\")\n  if [ \"$code\" -ne 200 ]; then\n    echo \"app-producer: publish failed: $(cat /tmp/pubresp)\"\n    exit 1\n  fi\n  i=$((i+1))\n  sleep 2\ndone\n"
--
    "image": "curlimages/curl:8.6.0",
    "imagePullPolicy": "IfNotPresent",
    "name": "producer",
    "resources": {},
    "terminationMessagePath": "/dev/termination-log",

